Plotly = require("https://cdn.plot.ly/plotly-latest.min.js")







// Data
Res_Elv = (await FileAttachment("Data/Reservoir_Elevation.csv").csv()).map(d =&gt; ({
  ...d,
  Year: +d.Year,
  Elevation: +d.Elevation,
}))








viewof reservoir_choice = Inputs.select(
  ["Lake Mead", "Lake Powell"],
  { label: "Reservoir:", value: "Lake Mead" }
)








filtered = Res_Elv.filter(d =&gt; d.Reservoir === reservoir_choice)

Elevation

{
  const div = html`&lt;div style="width: 100%; min-height: 750px;"&gt;&lt;/div&gt;`

  Plotly.newPlot(div, [
    {
      x: filtered.map(d =&gt; d.Year),
      y: filtered.map(d =&gt; d.Elevation),
      type: "scatter",
      mode: "lines",
      name: "Reservoir Elevation",
      line: { color: "blue", width: 2 }
    }
  ], {
    title: "Reservoir Elevation Over Time",
    xaxis: { title: "Year", tickformat: "d" },
    yaxis: { title: "Elevation (ft)" },
    font: { family: "sans-serif" },
    plot_bgcolor: "white",
    paper_bgcolor: "white",
    showlegend: true,
    legend: { x: 1, xanchor: "right", y: 1 }
  })

  return div
}
